public class Hotel {
    private int totalSuites;
    private int totalRooms;
    private int bookedSuites;
    private int bookedRooms;

    public Hotel(int totalSuites, int totalRooms) {
        this.totalSuites = totalSuites;
        this.totalRooms = totalRooms;
    }

    public int getAvailableSuites() { return totalSuites - bookedSuites; }
    public int getAvailableRooms() { return totalRooms - bookedRooms; }

    public boolean bookRooms(int suites, int rooms) {
        if (suites > getAvailableSuites() || rooms > getAvailableRooms()) return false;
        bookedSuites += suites;
        bookedRooms += rooms;
        return true;
    }
}

